ee:message.ee:set-payload:
%dw 2.0
// Output format is JSON
output application/json 

---
// Normalize JSON students
{
  // Static field representing the university name
  university: "Global Tech University",

  // Transform, then sort students alphabetically by fullName
  students: (
    (payload.students filter (s) -> s.age >= 22) // ✅ Filter: keep only students with age ≥ 22
    map (s) -> { // Iterate over each student in the input payload
      studentId: s.id, // Map 'id' → 'studentId'
      fullName: upper(s.name), // Convert 'name' to uppercase and map to 'fullName'

      age: s.age, // Keep 'age' as-is
      department: s.department, // Keep 'department' as-is
      status: "ACTIVE", // Add a constant field 'status'
      category:               // Add derived field 'category'
          if (s.age < 23)             // Condition: if age is less than 23
            "Junior"                  // Assign "Junior"
          else 
            "Senior"                  // Otherwise assign "Senior"
    }
  ) orderBy (s) -> s.fullName,  // Sort the transformed students by 'fullName' alphabetically

  // Count only filtered students (age ≥ 22)
  totalStudents: 
    sizeOf(payload.students filter (s) -> s.age >= 22)  // Count filtered records
}

%dw 2.0
// Output format is JSON
output application/json 

---
// Normalize JSON students
{
  // Static field representing the university name
  university: "Global Tech University",

  // Transform, then sort students alphabetically by fullName
  students: (
    (payload.students.*student filter (s) -> s.age >= 22) // ✅ Filter: keep only students with age ≥ 22
    map (s) -> { // Iterate over each student in the input payload
      studentId: s.id, // Map 'id' → 'studentId'
      fullName: upper(s.name), // Convert 'name' to uppercase and map to 'fullName'

      age: s.age as Number, // Keep 'age' as-is (cast to Number for logic)
      department: s.department, // Keep 'department' as-is
      status: "ACTIVE", // Add a constant field 'status'
      category:               // Add derived field 'category'
          if (s.age < 23)             // Condition: if age is less than 23
            "Junior"                  // Assign "Junior"
          else 
            "Senior"                  // Otherwise assign "Senior"
    }
  ) orderBy (s) -> s.fullName,  // Sort the transformed students by 'fullName' alphabetically

  // Count only filtered students (age ≥ 22)
  totalStudents: 
    sizeOf(payload.students.*student filter (s) -> s.age >= 22)  // Count filtered records
}

